// Generates per-page Open Graph images in public/og/<slug>.png
// Run: node scripts/generate-og-pages.mjs  (or via npm run build / npm run assets)
//
// Each chapter gets a 1200×630 PNG branded with its title and part label.
// The homepage uses the global public/og.png instead (generated by generate-assets.mjs).
import sharp from 'sharp';
import { readFile, mkdir } from 'node:fs/promises';
import { readdirSync, statSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const root = fileURLToPath(new URL('..', import.meta.url));
const docsDir = path.join(root, 'src/content/docs');
const outDir = path.join(root, 'public/og');

await mkdir(outDir, { recursive: true });

const CORAL  = '#ff7f66';
const WHITE  = '#ffffff';
const GRAY   = '#8c8c8c';
const WIRE   = '#2e2e2e';
const SITE   = 'securesoftwaredelivery.wckd14.xyz';

const PARTS = {
  'foundations':        'I — FOUNDATIONS',
  'source-trust':       'II — SOURCE TRUST',
  'build-trust':        'III — BUILD TRUST',
  'artifact-trust':     'IV — ARTIFACT TRUST',
  'deployment-trust':   'V — DEPLOYMENT TRUST',
  'runtime-trust':      'VI — RUNTIME TRUST',
  'platform-security':  'VII — PLATFORM SECURITY',
  'operations':         'VIII — OPERATIONS',
};

function escapeXml(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

// Split a title into at most two lines, cutting near the middle word boundary.
const MAX_LINE = 24;
function wrapTitle(title) {
  if (title.length <= MAX_LINE) return [title];
  const words = title.split(' ');
  const half = title.length / 2;
  let cumLen = 0;
  let bestSplit = 1;
  let bestDiff = Infinity;
  for (let i = 0; i < words.length - 1; i++) {
    cumLen += (i > 0 ? 1 : 0) + words[i].length;
    const diff = Math.abs(cumLen - half);
    if (diff < bestDiff) { bestDiff = diff; bestSplit = i + 1; }
  }
  return [words.slice(0, bestSplit).join(' '), words.slice(bestSplit).join(' ')];
}

function fontSize(title, isTwoLine) {
  if (isTwoLine) return 60;
  if (title.length <= 12) return 88;
  if (title.length <= 18) return 80;
  return 72;
}

function makeSvg(title, partLabel) {
  const lines    = wrapTitle(title);
  const twoLine  = lines.length > 1;
  const fs       = fontSize(title, twoLine);
  const lh       = Math.round(fs * 1.2);
  const partText = partLabel ? `PART ${partLabel}` : 'SSDA HANDBOOK';

  // Vertical positions — single-line and two-line layouts
  const barY    = twoLine ? 168 : 202;
  const barH    = twoLine ? 212 : 158;
  const partY   = twoLine ? 192 : 228;
  const title1Y = twoLine ? 268 : 336;
  const title2Y = title1Y + lh;

  const line1 = `<text x="100" y="${title1Y}" font-family="monospace" font-size="${fs}" font-weight="bold" fill="${WHITE}">${escapeXml(lines[0])}</text>`;
  const line2 = twoLine
    ? `<text x="100" y="${title2Y}" font-family="monospace" font-size="${fs}" font-weight="bold" fill="${WHITE}">${escapeXml(lines[1])}</text>`
    : '';

  return `<svg xmlns="http://www.w3.org/2000/svg" width="1200" height="630">
  <rect width="1200" height="630" fill="#000000"/>
  <rect x="40" y="40" width="1120" height="550" fill="none" stroke="${WIRE}" stroke-width="1" rx="10"/>
  <rect x="40" y="40" width="1120" height="6" fill="${CORAL}"/>
  <rect x="70" y="${barY}" width="6" height="${barH}" fill="${CORAL}"/>
  <text x="102" y="${partY}" font-family="monospace" font-size="22" letter-spacing="4" fill="${GRAY}">${escapeXml(partText)}</text>
  ${line1}
  ${line2}
  <text x="102" y="520" font-family="monospace" font-size="22" fill="${GRAY}">Developer <tspan fill="${CORAL}">&#8594;</tspan> Git <tspan fill="${CORAL}">&#8594;</tspan> Build <tspan fill="${CORAL}">&#8594;</tspan> Artifact <tspan fill="${CORAL}">&#8594;</tspan> Deployment <tspan fill="${CORAL}">&#8594;</tspan> Runtime</text>
  <text x="102" y="563" font-family="monospace" font-size="19" fill="#595959">${SITE}</text>
</svg>`;
}

// Parse frontmatter title from raw file content.
function parseTitle(content) {
  const m = content.match(/^---\n([\s\S]*?)\n---/);
  if (!m) return null;
  for (const line of m[1].split('\n')) {
    const colon = line.indexOf(':');
    if (colon < 0) continue;
    const key = line.slice(0, colon).trim();
    if (key === 'title') {
      return line.slice(colon + 1).trim().replace(/^["']|["']$/g, '');
    }
  }
  return null;
}

// Walk docs/ recursively, skipping index.mdx (homepage uses the global og.png).
function walkDocs(dir, prefix = '') {
  const results = [];
  for (const entry of readdirSync(dir)) {
    const full = path.join(dir, entry);
    if (statSync(full).isDirectory()) {
      results.push(...walkDocs(full, prefix ? `${prefix}/${entry}` : entry));
    } else if (/\.(mdx?)$/.test(entry) && entry !== 'index.mdx') {
      const slug = (prefix ? `${prefix}/` : '') + entry.replace(/\.(mdx?)$/, '');
      results.push({ full, slug });
    }
  }
  return results;
}

const pages = walkDocs(docsDir);
let count = 0;

for (const { full, slug } of pages) {
  const content = await readFile(full, 'utf8');
  const title   = parseTitle(content) || slug;
  const dir     = slug.includes('/') ? slug.split('/')[0] : null;
  const part    = dir ? PARTS[dir] : null;

  const svg     = makeSvg(title, part);
  const outPath = path.join(outDir, `${slug}.png`);

  await mkdir(path.dirname(outPath), { recursive: true });
  await sharp(Buffer.from(svg)).png().toFile(outPath);
  console.log(`  public/og/${slug}.png`);
  count++;
}

console.log(`\nWrote ${count} per-page OG images to public/og/`);
